/**
 * City packet handlers.
 */
import { store } from '../../data/store';
import type { City } from '../../data/types';
import { BitVector } from '../../utils/bitvector';
import { C_S_RUNNING, clientState, clientIsObserver, clientPlaying } from '../../client/clientState';
import { cityUnhappy, removeCity } from '../../data/city';
import { mark_tile_dirty } from '../../renderer/mapviewCommon';
import { mark_overview_dirty } from '../../core/overview';
import { show_city_dialog_by_id, city_name_dialog, city_trade_routes } from '../../ui/cityDialog';
import { globalEvents } from '../../core/events';
import type {
  BasePacket,
  CityInfoPacket, CityShortInfoPacket, CityNationalitiesPacket,
  CityRallyPointPacket, WebCityInfoAdditionPacket, CityUpdateCountersPacket,
  CityRemovePacket, CityNameSuggestionInfoPacket, CitySabotageListPacket,
} from './packetTypes';

const REQEST_PLAYER_INITIATED = 0;

export function handle_city_info(packet: CityInfoPacket): void {
  if (typeof mark_tile_dirty === 'function' && packet['tile'] != null) {
    mark_tile_dirty(packet['tile']);
  }
  mark_overview_dirty();

  packet['name'] = decodeURIComponent(packet['name']);
  packet['improvements'] = new BitVector(packet['improvements'] as number[]);
  packet['city_options'] = new BitVector(packet['city_options'] as number[]);
  packet['unhappy'] = cityUnhappy(packet as unknown as City);

  if (store.cities[packet['id']] == null) {
    const pcity = packet;
    store.cities[packet['id']] = packet as unknown as City;
    if (C_S_RUNNING === clientState() && !store.observing && store.benchmarkStart === 0
        && !clientIsObserver() && packet['owner'] === clientPlaying()?.playerno) {
      show_city_dialog_by_id(packet['id']);
    }
  } else {
    Object.assign(store.cities[packet['id']], packet);
  }

  const pcity = store.cities[packet['id']];
  pcity['shield_stock_changed'] = false;
  pcity['production_changed'] = false;
  globalEvents.emit('city:updated', packet);
}

export function handle_city_nationalities(packet: CityNationalitiesPacket): void {
  if (store.cities[packet['id']] != null) {
    Object.assign(store.cities[packet['id']], packet);
  }
}

export function handle_city_rally_point(packet: CityRallyPointPacket): void {
  if (store.cities[packet['id']] != null) {
    Object.assign(store.cities[packet['id']], packet);
  }
}

export function handle_web_city_info_addition(packet: WebCityInfoAdditionPacket): void {
  if (store.cities[packet['id']] != null) {
    Object.assign(store.cities[packet['id']], packet);
  }
  // update_city_info_dialog was a legacy UI function — removed in observer mode
}

export function handle_city_short_info(packet: CityShortInfoPacket): void {
  if (typeof mark_tile_dirty === 'function' && packet['tile'] != null) {
    mark_tile_dirty(packet['tile']);
  }

  packet['name'] = decodeURIComponent(packet['name']);
  packet['improvements'] = new BitVector(packet['improvements'] as number[]);

  if (store.cities[packet['id']] == null) {
    store.cities[packet['id']] = packet as unknown as City;
  } else {
    Object.assign(store.cities[packet['id']], packet);
  }
  globalEvents.emit('city:updated', packet);
}

export function handle_city_update_counters(packet: CityUpdateCountersPacket): void {
  if (store.cities[packet['id']] != null) {
    store.cities[packet['id']]['counters'] = packet['counters'];
  }
}

export function handle_city_update_counter(_packet: BasePacket): void { /* TODO */ }

export function handle_city_remove(packet: CityRemovePacket): void {
  removeCity(packet['city_id']);
  // removeCity only emits city:removed for player-owned cities; always emit
  // here so the cityCount signal stays correct in observer mode.
  globalEvents.emit('city:removed', packet['city_id']);
}

export function handle_city_name_suggestion_info(packet: CityNameSuggestionInfoPacket): void {
  packet['name'] = decodeURIComponent(packet['name']);
  city_name_dialog(packet['name'], packet['unit_id']);
}

export function handle_city_sabotage_list(_packet: CitySabotageListPacket): void {
  // player-only: sabotage dialog — no-op in observer mode
}
